const initialProducts = [
  { id: 1, name: 'Laptop', price: 999, inventory: 18, availability: 'In stock' },
  { id: 2, name: 'Phone', price: 699, inventory: 42, availability: 'In stock' },
  { id: 3, name: 'Tablet', price: 499, inventory: 11, availability: 'Low stock' },
  { id: 4, name: 'Headphones', price: 199, inventory: 0, availability: 'Out of stock' },
  { id: 5, name: 'Watch', price: 299, inventory: 24, availability: 'In stock' }
];

let products = initialProducts;

export async function getAllProducts() {
  // Simulate an upstream read with modest latency.
  await new Promise((resolve) => setTimeout(resolve, 100));

  return products;
}

export async function syncLatestProducts() {
  // Simulate an ERP/PIM refresh that updates shared catalog data.
  await new Promise((resolve) => setTimeout(resolve, 150));

  products = products.map((product) => ({
    ...product,
    price: Math.round(product.price * 1.02),
    inventory: Math.max(0, product.inventory - 1),
    availability:
      product.inventory <= 1 ? 'Out of stock' : product.inventory <= 10 ? 'Low stock' : 'In stock'
  }));
}

