.hero {
  display: flex;
  justify-content: space-between;
  gap: 24px;
  align-items: end;
  margin-bottom: 28px;
}

.eyebrow {
  margin: 0 0 12px;
  text-transform: uppercase;
  letter-spacing: 0.16em;
  font-size: 12px;
  color: #93c5fd;
}

h1 {
  margin: 0;
  font-size: clamp(2.4rem, 5vw, 4.8rem);
  line-height: 0.95;
  letter-spacing: -0.05em;
}

.lede {
  max-width: 68ch;
  margin: 16px 0 0;
  color: #cbd5e1;
  font-size: 1.02rem;
  line-height: 1.6;
}

.sync-button {
  border: 0;
  border-radius: 999px;
  background: linear-gradient(135deg, #f8fafc, #cbd5e1);
  color: #0f172a;
  padding: 14px 18px;
  font-weight: 700;
  cursor: pointer;
  box-shadow: 0 12px 30px rgba(15, 23, 42, 0.25);
}

.panel {
  background: rgba(15, 23, 42, 0.72);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 24px;
  padding: 20px;
  backdrop-filter: blur(20px);
}

.panel-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}

.panel-header h2 {
  margin: 0;
  font-size: 1.1rem;
}

.panel-header span {
  color: #94a3b8;
  font-size: 0.95rem;
}

.table {
  display: grid;
  gap: 8px;
}

.table-row {
  display: grid;
  grid-template-columns: 2fr 1fr 1fr 1fr;
  gap: 16px;
  padding: 14px 16px;
  border-radius: 16px;
  background: rgba(30, 41, 59, 0.75);
}

.table-head {
  background: transparent;
  color: #93c5fd;
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
}

@media (max-width: 720px) {
  .hero {
    flex-direction: column;
    align-items: start;
  }

  .table-row {
    grid-template-columns: 1.4fr 1fr;
  }

  .table-head {
    display: none;
  }
}

